async awaitConfig(file: string): Promise<SvelteConfig | undefined> {
    const config = this.getConfig(file);
    if (config) {
        return config;
    }

    const fileDirectory = this.path.dirname(file);
    const configPath = this.searchConfigPathUpwards(fileDirectory);
    if (configPath) {
        await this.loadAndCacheConfig(configPath, fileDirectory);
    } else {
        await this.addFallbackConfig(fileDirectory);
    }
    return this.getConfig(file);
}

export function path_matches(path, constraint) {
	if (!constraint) return true;

	const normalized = constraint.endsWith('/') ? constraint.slice(0, -1) : constraint;

	if (path === normalized) return true;
	return path.startsWith(normalized + '/');
}

push(value) {
	if (this.#closed) return;
	for (const subscriber of this.#subscribers) {
		if (subscriber.waiting_resolve) {
			const resolve = subscriber.waiting_resolve;
			subscriber.waiting_resolve = null;
			subscriber.waiting_reject = null;
			resolve({ value, done: false });
		} else {
			subscriber.pending = { value };
		}
	}
}

constructor(status, location) {
	try {
		new Headers({ location });
	} catch {
		throw new Error(
			`Invalid redirect location ${JSON.stringify(location)}: ` +
				'this string contains characters that cannot be used in HTTP headers'
		);
	}

	this.status = status;
	this.location = location;
}

async ({ event, resolve }) => {
	const session = await auth.api.getSession({
		headers: event.request.headers,
	});

	event.locals.session = session ? session.session : null;
	event.locals.user = session ? session.user : null;

	return svelteKitHandler({
		event,
		resolve,
		auth,
		building,
	});
}

constructor(name, type, size, last_modified, get_chunk, offset) {
	this.name = name;
	this.type = type;
	this.size = size;
	this.lastModified = last_modified;
	this.webkitRelativePath = '';
	this.#get_chunk = get_chunk;
	this.#offset = offset;

	// TODO - hacky, required for private members to be accessed on proxy
	this.arrayBuffer = this.arrayBuffer.bind(this);
	this.bytes = this.bytes.bind(this);
	this.slice = this.slice.bind(this);
	this.stream = this.stream.bind(this);
	this.text = this.text.bind(this);
}

export default async function handler(request, context) {
	if (!origin) {
		origin = new URL(request.url).origin;
		await initialized;
	}

	return server.respond(request, {
		platform: { context },
		getClientAddress() {
			return context.ip;
		}
	});
}

function initCodingStyle() {
	const defaultWritable = writable<CodingStyle>('tailwind' in code ? 'tailwind' : 'css');
	if (!isBrowser) return defaultWritable;
	const preferredStyle = localStorage.getItem('melt-coding-style') as CodingStyle | null;
	if (isCodingStyle(preferredStyle)) {
		return writable<CodingStyle>(preferredStyle);
	}
	return writable<CodingStyle>('tailwind' in code ? 'tailwind' : 'css');
}

function transformCss(s: MagicString, css: AST.CSS.StyleSheet | null) {
	if (!css) {
		return;
	}
	try {
		const transformed = transformStylesheet(s.original.slice(css.content.start, css.content.end));
		s.overwrite(css.content.start, css.content.end, transformed.code);
	} catch (error) {
		log.warn(`Failed to transform CSS in Svelte component, skipping: ${error instanceof Error ? error.message : 'Unknown error'}`);
	}
}
